def di_chuyen(huong):
    if thang:
        return
    x_moi = rua.xcor()
    y_moi = rua.ycor()
    if huong == 90:
        y_moi = y_moi + BUOC
    elif huong == 270:
        y_moi = y_moi - BUOC
    elif huong == 180:
        x_moi = x_moi - BUOC
    elif huong == 0:
        x_moi = x_moi + BUOC
    rua.setheading(huong)
    if cham_tuong(x_moi, y_moi):
        return
    rua.goto(x_moi, y_moi)
    kiem_tra_thang()
    man_hinh.update()
